"use strict";const e=require("../common/vendor.js"),t=e.defineStore("user",{state:()=>({openid:"",phone:"",role:"",authorized_roles:[],name:"",avatar:"",community:"",isLogin:!1,manuallyLoggedOut:!1}),getters:{isPolice:e=>"派出所"===e.role,isStreet:e=>"街道"===e.role,isCommunity:e=>"社区"===e.role,isAdmin:e=>"管理员"===e.role,hasMultipleRoles:e=>e.authorized_roles&&e.authorized_roles.length>1},actions:{setUser(e){this.openid=e.openid||"",this.phone=e.phone||"",this.role=e.role||"",this.authorized_roles=e.authorized_roles||[],this.name=e.name||"",this.avatar=e.avatar||"",this.community=e.community||"",this.isLogin=!0,this.manuallyLoggedOut=!1},switchRole(e){this.authorized_roles.includes(e)&&(this.role=e)},clearUser(){this.openid="",this.role="",this.authorized_roles=[],this.name="",this.avatar="",this.community="",this.isLogin=!1},logout(){this.clearUser(),this.manuallyLoggedOut=!0,e.index.reLaunch({url:"/pages/login/index"})}},persist:{enabled:!0,strategies:[{key:"user",storage:{getItem:t=>e.index.getStorageSync(t),setItem:(t,i)=>e.index.setStorageSync(t,i),removeItem:t=>e.index.removeStorageSync(t)}}]}});exports.useUserStore=t;
